const products = [
  {
    name: "Royal Asante Kente",
    price: "$180",
    image: "/products/kente1.jpg",
  },
  {
    name: "GTP Premium Print",
    price: "$45",
    image: "/products/gtp1.jpg",
  },
  {
    name: "Vlisco Holland Gold",
    price: "$95",
    image: "/products/vlisco1.jpg",
  },
  {
    name: "ABC SUPER Classic",
    price: "$65",
    image: "/products/abc1.jpg",
  },
];

export default function BestSellers() {
  return (
    <section className="bg-black py-24">
      <div className="mx-auto max-w-7xl px-6">
        <p className="text-center text-sm font-bold uppercase tracking-[0.3em] text-[#d4af37]">
          Best Sellers
        </p>

        <h2 className="mt-4 text-center text-5xl font-bold text-white">
          Customer Favorites
        </h2>

        <div className="mt-14 grid gap-8 md:grid-cols-2 lg:grid-cols-4">
          {products.map((product) => (
            <div
              key={product.name}
              className="overflow-hidden rounded-2xl border border-white/10 bg-[#111111]"
            >
              <div className="h-72 bg-[#1a1a1a]"></div>

              <div className="p-6">
                <h3 className="text-xl font-semibold text-white">
                  {product.name}
                </h3>

                <p className="mt-2 text-[#d4af37]">
                  Starting from {product.price}
                </p>

                <button className="mt-5 w-full rounded-lg bg-[#d4af37] py-3 font-semibold text-black hover:bg-[#e4bf47]">
                  View Product
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}